function processData() {
  // 获取输入数据
  const inputArray = $input.all().filter(item => item.json);

  // 定义procedure_detail_id到procedure_name的映射
  const procedureNameMapping = {
    '81': ['制箱', '扫描', '装箱', '封箱'],
    '79': ['合彩盒', '装封套', '称重']
  };

  // 使用map函数处理每个元素
  const outputArray = inputArray.map(entry => {
    const item = entry.json; // 提取json字段中的内容

    // 获取procedure_detail_id并转换为字符串
    const procedureDetailId = item.procedure_detail_id.toString();

    // 根据procedure_detail_id设置procedure_name
    let procedureName = item.data?.procedure_name || '';
    if (procedureNameMapping[procedureDetailId]) {
      // 如果有映射关系，使用映射的值
      procedureName = procedureNameMapping[procedureDetailId].join('、');
    }

    // 获取bind_id并根据不同procedure_detail_id进行不同处理
    let bindingData = item.data?.bind_id || '';

    if (procedureDetailId === '81') {
      // 对于id=81的数据，在后面拼接";"
      bindingData = bindingData ? `箱号：${bindingData}` : '';
    } else if (procedureDetailId === '79') {
      // 对于id=79的数据，判断最后一位是否为'g'
      if (bindingData && !bindingData.endsWith('g')) {
        bindingData = `${bindingData}g`;
      }
    }

    // 构造输出对象
    return {
      procedure_name: procedureName,
      createtime: item.createtime,
      machine_data_id: item.machine_data_id.toString(),
      binding_action: "1",
      binding_data: bindingData,
      procedure_detail_id: procedureDetailId,
      machine_data_id_old: ''
    };
  });

  // 返回最终的输出数组
  return outputArray;
}

// 调用并获取结果
const result = processData();
console.log("Processed Output:", JSON.stringify(result, null, 2));

// 返回结果
return result;

